const req = $('Prepare Prompt').item.json;
const llmRes = $input.first().json;

let quality_report = {
  ghost_probability: 0,
  ghost_reasons: [],
  scam_risk: 0,
  scam_reasons: [],
  confidence_score: 50
};

if (llmRes.choices && llmRes.choices.length > 0) {
  try {
    const parsed = JSON.parse(llmRes.choices[0].message.content);
    quality_report = { ...quality_report, ...parsed, confidence_score: 90 };
  } catch (e) {
    quality_report.ghost_reasons.push('LLM parsing failed');
  }
} else {
  quality_report.ghost_reasons.push('LLM request failed');
}

req.job.quality_report = req.job.quality_report || {};
Object.assign(req.job.quality_report, quality_report);

return [{ json: req.job }];
